final:
module RefModule (
    input wire Clk,
    input wire En,
    input wire Rst,
    output reg [1:0] Q
    );

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge Clk or posedge dbg_halt) begin
    if (Rst)
        Q <= 2'b00;
    else if (En)
        Q <= Q + 1;
end

endmodule
